(29, 'support_display', '[{\"icon\": \"fas fa-headset\",\"title\": \"24/7 Support\",\"description\": \"Our ERP system comes with a dedicated support team available 24/7 to assist with any issues or questions you may have. We are here to ensure that your experience with our ERP system is smooth and trouble-free.\",\"title_url\": \"\"},{\"icon\": \"fas fa-book\",\"title\": \"Comprehensive Documentation\",\"description\": \"We provide detailed documentation and user guides to help you navigate and utilize all the features of our ERP system effectively. Our documentation covers everything from initial setup to advanced customization.\",\"title_url\": \"\"},{\"icon\": \"fas fa-graduation-cap\",\"title\": \"Training Programs\",\"description\": \"We offer training programs to help your team get up to speed with our ERP system. Our training sessions are designed to be interactive and hands-on, ensuring that your team is well-equipped to make the most of our software.\",\"title_url\": \"\"}]', '2024-06-08 05:56:20', '2024-06-08 05:56:20'),
