INSERT INTO `noc_certificates` (`id`, `lang`, `content`, `created_by`, `created_at`, `updated_at`) VALUES
(1, 'ar', '<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\n\n\n\n            <p>التاريخ: {date}</p>\n\n\n\n            <p>إلى من يهمه الأمر</p>\n\n\n\n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\n\n\n\n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\n\n\n\n            <p>بإخلاص،</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>التوقيع</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(2, 'zh', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\n\n            <p>日期：{日期}</p>\n\n            <p>致任何可能关心的人</p>\n\n            <p>如果{employee_name}女士/先生加入任何其他组织并向其提供服务，此证书将用于为她/他申请无异议证书 (NoC)。据了解，她/他已结清了所有余额并从 {app_name} 公司收到了她/他的保证金。</p>\n\n            <p>我们祝她/他未来好运。</p>\n\n            <p>真诚的，</p>\n            <p>{employee_name}</p>\n            <p>{名称}</p>\n            <p>签名</p>\n            <p>{应用名称}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(3, 'da', '<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\n\n\n\n            <p>Dato: {date}</p>\n\n\n\n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\n\n\n\n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\n\n\n\n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\n\n\n\n            <p>Med venlig hilsen</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Underskrift</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(4, 'de', '<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\n\n\n\n            <p>Datum {date}</p>\n\n\n\n            <p>Wen auch immer es betrifft</p>\n\n\n\n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\n\n\n\n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\n\n\n\n            <p>Aufrichtig,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Unterschrift</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(5, 'en', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\n\n            <p>Date: {date}</p>\n\n            <p>To Whomsoever It May Concern</p>\n\n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\n\n            <p>We wish her/him good luck in the future.</p>\n\n            <p>Sincerely,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>Signature</p>\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(6, 'es', '<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\n\n\n\n            <p>Fecha: {date}</p>\n\n\n\n            <p>A quien corresponda</p>\n\n\n\n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\n\n\n\n            <p>Le deseamos buena suerte en el futuro.</p>\n\n\n\n            <p>Sinceramente,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Firma</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(7, 'fr', '<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\n\n\n            <p>Date : {date}</p>\n\n\n            <p>&Agrave; toute personne concern&eacute;e</p>\n\n\n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\n\n\n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\n\n\n            <p>Sinc&egrave;rement,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Signature</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(8, 'he', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אישור ללא התנגדות</strong></span></p>\n\n            <p>תאריך: {date}</p>\n\n            <p>למי שזה נוגע לעניין</p>\n\n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב /מר {employee_name} אם היא/הוא מצטרף ומספק את שירותיה לכל ארגון אחר. זה מודיע כי היא/הוא סולקה את כל היתרות שלה/שלו וקיבלה את האבטחה שלה/שלו מחברת {app_name}.</p>\n\n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\n\n            <p>בכבוד רב,</p>\n            <p>{employee_name}</p>\n            <p>{designation}</p>\n            <p>חתימה</p>\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(9, 'it', '<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\n\n\n\n            <p>Data: {date}</p>\n\n\n\n            <p>A chi pu&ograve; interessare</p>\n\n\n\n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\n\n\n\n            <p>Le auguriamo buona fortuna per il futuro.</p>\n\n\n\n            <p>Cordiali saluti,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Firma</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(10, 'ja', '<h3 style=\"text-align: center;\">異議なし証明書</h3>\n\n\n\n            <p>日付: {date}</p>\n\n\n\n            <p>関係者各位</p>\n\n\n\n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\n\n\n\n            <p>彼女/彼の今後の幸運を祈っています。</p>\n\n\n\n            <p>心から、</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>サイン</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(11, 'nl', '<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\n\n\n\n            <p>Datum: {date}</p>\n\n\n\n            <p>Aan wie het ook aangaat</p>\n\n\n\n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\n\n\n\n            <p>We wensen haar/hem veel succes in de toekomst.</p>\n\n\n\n            <p>Eerlijk,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Handtekening</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(12, 'pl', '<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\n\n\n\n            <p>Data: {date}</p>\n\n\n\n            <p>Do kogo to może dotyczyć</p>\n\n\n\n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\n\n\n\n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\n\n\n\n            <p>Z poważaniem,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Podpis</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(13, 'pt', '<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n\n\n\n            <p>Data: {date}</p>\n\n\n\n            <p>A quem interessar</p>\n\n\n\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n\n\n\n            <p>Desejamos-lhe boa sorte no futuro.</p>\n\n\n\n            <p>Sinceramente,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Assinatura</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(14, 'ru', '<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\n\n\n\n            <p>Дата: {date}</p>\n\n\n\n            <p>Кого бы это ни касалось</p>\n\n\n\n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\n\n\n\n            <p>Мы желаем ей/ему удачи в будущем.</p>\n\n\n\n            <p>Искренне,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Подпись</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(15, 'tr', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Sertifikası</strong></span></p>\n\n            <p>Tarih: {tarih</p>\n\n            <p>İlgilendiği Kişiye</p>\n\n            <p>Bu sertifika, {employee_name} Hanımefendi başka bir kuruluşa katılır ve hizmetlerini sunarsa, İtiraz Yok Sertifikası (NoC) talep etmek içindir. Tüm bakiyelerini kapattığı ve teminatını {app_name} Şirketinden aldığı bilgisi verilir.</p>\n\n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\n\n            <p>Saygılarımızla,</p>\n            <p>{çalışan_adı}</p>\n            <p>{gösterim</p>\n            <p>İmza</p>\n            <p>{uygulama_adı}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(16, 'pt-br', '<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\n\n            <p>Data: {date}</p>\n\n            <p>A quem interessar</p>\n\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\n\n            <p>Desejamos-lhe boa sorte no futuro.</p>\n\n            <p>Sinceramente,</p>\n\n            <p>{employee_name}</p>\n\n            <p>{designation}</p>\n\n            <p>Assinatura</p>\n\n            <p>{app_name}</p>', 2, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(17, 'ar', '<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\r\n\r\n\r\n\r\n            <p>التاريخ: {date}</p>\r\n\r\n\r\n\r\n            <p>إلى من يهمه الأمر</p>\r\n\r\n\r\n\r\n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\r\n\r\n\r\n\r\n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\r\n\r\n\r\n\r\n            <p>بإخلاص،</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>التوقيع</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(18, 'zh', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\r\n\r\n            <p>日期：{日期}</p>\r\n\r\n            <p>致任何可能关心的人</p>\r\n\r\n            <p>如果{employee_name}女士/先生加入任何其他组织并向其提供服务，此证书将用于为她/他申请无异议证书 (NoC)。据了解，她/他已结清了所有余额并从 {app_name} 公司收到了她/他的保证金。</p>\r\n\r\n            <p>我们祝她/他未来好运。</p>\r\n\r\n            <p>真诚的，</p>\r\n            <p>{employee_name}</p>\r\n            <p>{名称}</p>\r\n            <p>签名</p>\r\n            <p>{应用名称}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(19, 'da', '<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\r\n\r\n\r\n\r\n            <p>Dato: {date}</p>\r\n\r\n\r\n\r\n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\r\n\r\n\r\n\r\n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\r\n\r\n\r\n\r\n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\r\n\r\n\r\n\r\n            <p>Med venlig hilsen</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Underskrift</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(20, 'de', '<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\r\n\r\n\r\n\r\n            <p>Datum {date}</p>\r\n\r\n\r\n\r\n            <p>Wen auch immer es betrifft</p>\r\n\r\n\r\n\r\n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\r\n\r\n\r\n\r\n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\r\n\r\n\r\n\r\n            <p>Aufrichtig,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Unterschrift</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(21, 'en', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\r\n\r\n            <p>Date: {date}</p>\r\n\r\n            <p>To Whomsoever It May Concern</p>\r\n\r\n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\r\n\r\n            <p>We wish her/him good luck in the future.</p>\r\n\r\n            <p>Sincerely,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>Signature</p>\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(22, 'es', '<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\r\n\r\n\r\n\r\n            <p>Fecha: {date}</p>\r\n\r\n\r\n\r\n            <p>A quien corresponda</p>\r\n\r\n\r\n\r\n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\r\n\r\n\r\n\r\n            <p>Le deseamos buena suerte en el futuro.</p>\r\n\r\n\r\n\r\n            <p>Sinceramente,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Firma</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(23, 'fr', '<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\r\n\r\n\r\n            <p>Date : {date}</p>\r\n\r\n\r\n            <p>&Agrave; toute personne concern&eacute;e</p>\r\n\r\n\r\n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\r\n\r\n\r\n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\r\n\r\n\r\n            <p>Sinc&egrave;rement,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Signature</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(24, 'he', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אישור ללא התנגדות</strong></span></p>\r\n\r\n            <p>תאריך: {date}</p>\r\n\r\n            <p>למי שזה נוגע לעניין</p>\r\n\r\n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב /מר {employee_name} אם היא/הוא מצטרף ומספק את שירותיה לכל ארגון אחר. זה מודיע כי היא/הוא סולקה את כל היתרות שלה/שלו וקיבלה את האבטחה שלה/שלו מחברת {app_name}.</p>\r\n\r\n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\r\n\r\n            <p>בכבוד רב,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>חתימה</p>\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(25, 'it', '<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\r\n\r\n\r\n\r\n            <p>Data: {date}</p>\r\n\r\n\r\n\r\n            <p>A chi pu&ograve; interessare</p>\r\n\r\n\r\n\r\n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Le auguriamo buona fortuna per il futuro.</p>\r\n\r\n\r\n\r\n            <p>Cordiali saluti,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Firma</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(26, 'ja', '<h3 style=\"text-align: center;\">異議なし証明書</h3>\r\n\r\n\r\n\r\n            <p>日付: {date}</p>\r\n\r\n\r\n\r\n            <p>関係者各位</p>\r\n\r\n\r\n\r\n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\r\n\r\n\r\n\r\n            <p>彼女/彼の今後の幸運を祈っています。</p>\r\n\r\n\r\n\r\n            <p>心から、</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>サイン</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(27, 'nl', '<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\r\n\r\n\r\n\r\n            <p>Datum: {date}</p>\r\n\r\n\r\n\r\n            <p>Aan wie het ook aangaat</p>\r\n\r\n\r\n\r\n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\r\n\r\n\r\n\r\n            <p>We wensen haar/hem veel succes in de toekomst.</p>\r\n\r\n\r\n\r\n            <p>Eerlijk,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Handtekening</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(28, 'pl', '<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\r\n\r\n\r\n\r\n            <p>Data: {date}</p>\r\n\r\n\r\n\r\n            <p>Do kogo to może dotyczyć</p>\r\n\r\n\r\n\r\n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\r\n\r\n\r\n\r\n            <p>Z poważaniem,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Podpis</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(29, 'pt', '<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n\r\n\r\n\r\n            <p>Data: {date}</p>\r\n\r\n\r\n\r\n            <p>A quem interessar</p>\r\n\r\n\r\n\r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n\r\n\r\n\r\n            <p>Sinceramente,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Assinatura</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(30, 'ru', '<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\r\n\r\n\r\n\r\n            <p>Дата: {date}</p>\r\n\r\n\r\n\r\n            <p>Кого бы это ни касалось</p>\r\n\r\n\r\n\r\n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Мы желаем ей/ему удачи в будущем.</p>\r\n\r\n\r\n\r\n            <p>Искренне,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Подпись</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(31, 'tr', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Sertifikası</strong></span></p>\r\n\r\n            <p>Tarih: {tarih</p>\r\n\r\n            <p>İlgilendiği Kişiye</p>\r\n\r\n            <p>Bu sertifika, {employee_name} Hanımefendi başka bir kuruluşa katılır ve hizmetlerini sunarsa, İtiraz Yok Sertifikası (NoC) talep etmek içindir. Tüm bakiyelerini kapattığı ve teminatını {app_name} Şirketinden aldığı bilgisi verilir.</p>\r\n\r\n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\r\n\r\n            <p>Saygılarımızla,</p>\r\n            <p>{çalışan_adı}</p>\r\n            <p>{gösterim</p>\r\n            <p>İmza</p>\r\n            <p>{uygulama_adı}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(32, 'pt-br', '<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n\r\n            <p>Data: {date}</p>\r\n\r\n            <p>A quem interessar</p>\r\n\r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n\r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n\r\n            <p>Sinceramente,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Assinatura</p>\r\n\r\n            <p>{app_name}</p>', 5, '2024-06-10 04:03:53', '2024-06-10 04:03:53'),
(33, 'ar', '<h3 style=\"text-align: center;\">شهادة عدم ممانعة</h3>\r\n\r\n\r\n\r\n            <p>التاريخ: {date}</p>\r\n\r\n\r\n\r\n            <p>إلى من يهمه الأمر</p>\r\n\r\n\r\n\r\n            <p>هذه الشهادة مخصصة للمطالبة بشهادة عدم ممانعة (NoC) للسيدة / السيد {employee_name} إذا انضمت إلى أي مؤسسة أخرى وقدمت خدماتها / خدماتها. يتم إبلاغه لأنه قام بتصفية جميع أرصدته واستلام أمانه من شركة {app_name}.</p>\r\n\r\n\r\n\r\n            <p>نتمنى لها / لها التوفيق في المستقبل.</p>\r\n\r\n\r\n\r\n            <p>بإخلاص،</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>التوقيع</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(34, 'zh', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>无异议证书</strong></span></p>\r\n\r\n            <p>日期：{日期}</p>\r\n\r\n            <p>致任何可能关心的人</p>\r\n\r\n            <p>如果{employee_name}女士/先生加入任何其他组织并向其提供服务，此证书将用于为她/他申请无异议证书 (NoC)。据了解，她/他已结清了所有余额并从 {app_name} 公司收到了她/他的保证金。</p>\r\n\r\n            <p>我们祝她/他未来好运。</p>\r\n\r\n            <p>真诚的，</p>\r\n            <p>{employee_name}</p>\r\n            <p>{名称}</p>\r\n            <p>签名</p>\r\n            <p>{应用名称}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(35, 'da', '<h3 style=\"text-align: center;\">Ingen indsigelsesattest</h3>\r\n\r\n\r\n\r\n            <p>Dato: {date}</p>\r\n\r\n\r\n\r\n            <p>Til hvem det m&aring;tte vedr&oslash;re</p>\r\n\r\n\r\n\r\n            <p>Dette certifikat er for at g&oslash;re krav p&aring; et No Objection Certificate (NoC) for Ms. / Mr. {employee_name}, hvis hun/han tilslutter sig og leverer sine tjenester til enhver anden organisation. Det informeres, da hun/han har udlignet alle sine saldi og modtaget sin sikkerhed fra {app_name}-virksomheden.</p>\r\n\r\n\r\n\r\n            <p>Vi &oslash;nsker hende/ham held og lykke i fremtiden.</p>\r\n\r\n\r\n\r\n            <p>Med venlig hilsen</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Underskrift</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(36, 'de', '<h3 style=\"text-align: center;\">Kein Einwand-Zertifikat</h3>\r\n\r\n\r\n\r\n            <p>Datum {date}</p>\r\n\r\n\r\n\r\n            <p>Wen auch immer es betrifft</p>\r\n\r\n\r\n\r\n            <p>Dieses Zertifikat soll ein Unbedenklichkeitszertifikat (NoC) f&uuml;r Frau / Herrn {employee_name} beanspruchen, wenn sie/er einer anderen Organisation beitritt und ihre/seine Dienste anbietet. Sie wird informiert, da sie/er alle ihre/seine Guthaben ausgeglichen und ihre/seine Sicherheit von der Firma {app_name} erhalten hat.</p>\r\n\r\n\r\n\r\n            <p>Wir w&uuml;nschen ihr/ihm viel Gl&uuml;ck f&uuml;r die Zukunft.</p>\r\n\r\n\r\n\r\n            <p>Aufrichtig,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Unterschrift</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(37, 'en', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>No Objection Certificate</strong></span></p>\r\n\r\n            <p>Date: {date}</p>\r\n\r\n            <p>To Whomsoever It May Concern</p>\r\n\r\n            <p>This certificate is to claim a No Objection Certificate (NoC) for Ms. / Mr. {employee_name} if she/he joins and provides her/his services to any other organization. It is informed as she/he has cleared all her/his balances and received her/his security from {app_name} Company.</p>\r\n\r\n            <p>We wish her/him good luck in the future.</p>\r\n\r\n            <p>Sincerely,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>Signature</p>\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(38, 'es', '<h3 style=\"text-align: center;\">Certificado de conformidad</h3>\r\n\r\n\r\n\r\n            <p>Fecha: {date}</p>\r\n\r\n\r\n\r\n            <p>A quien corresponda</p>\r\n\r\n\r\n\r\n            <p>Este certificado es para reclamar un Certificado de No Objeci&oacute;n (NoC) para la Sra. / Sr. {employee_name} si ella / &eacute;l se une y brinda sus servicios a cualquier otra organizaci&oacute;n. Se informa que &eacute;l/ella ha liquidado todos sus saldos y recibido su seguridad de {app_name} Company.</p>\r\n\r\n\r\n\r\n            <p>Le deseamos buena suerte en el futuro.</p>\r\n\r\n\r\n\r\n            <p>Sinceramente,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Firma</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(39, 'fr', '<h3 style=\"text-align: center;\">Aucun certificat dopposition</h3>\r\n\r\n\r\n            <p>Date : {date}</p>\r\n\r\n\r\n            <p>&Agrave; toute personne concern&eacute;e</p>\r\n\r\n\r\n            <p>Ce certificat sert &agrave; r&eacute;clamer un certificat de non-objection (NoC) pour Mme / M. {employee_name} sil rejoint et fournit ses services &agrave; toute autre organisation. Il est inform&eacute; quil a sold&eacute; tous ses soldes et re&ccedil;u sa garantie de la part de la soci&eacute;t&eacute; {app_name}.</p>\r\n\r\n\r\n            <p>Nous lui souhaitons bonne chance pour lavenir.</p>\r\n\r\n\r\n            <p>Sinc&egrave;rement,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Signature</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(40, 'he', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>אישור ללא התנגדות</strong></span></p>\r\n\r\n            <p>תאריך: {date}</p>\r\n\r\n            <p>למי שזה נוגע לעניין</p>\r\n\r\n            <p>תעודה זו מיועדת לתבוע אישור ללא התנגדות (NoC) עבור גב /מר {employee_name} אם היא/הוא מצטרף ומספק את שירותיה לכל ארגון אחר. זה מודיע כי היא/הוא סולקה את כל היתרות שלה/שלו וקיבלה את האבטחה שלה/שלו מחברת {app_name}.</p>\r\n\r\n            <p>אנו מאחלים לו/לה בהצלחה בעתיד.</p>\r\n\r\n            <p>בכבוד רב,</p>\r\n            <p>{employee_name}</p>\r\n            <p>{designation}</p>\r\n            <p>חתימה</p>\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(41, 'it', '<h3 style=\"text-align: center;\">Certificato di nulla osta</h3>\r\n\r\n\r\n\r\n            <p>Data: {date}</p>\r\n\r\n\r\n\r\n            <p>A chi pu&ograve; interessare</p>\r\n\r\n\r\n\r\n            <p>Questo certificato serve a richiedere un certificato di non obiezione (NoC) per la signora / il signor {employee_name} se si unisce e fornisce i suoi servizi a qualsiasi altra organizzazione. Viene informato in quanto ha liquidato tutti i suoi saldi e ricevuto la sua sicurezza dalla societ&agrave; {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Le auguriamo buona fortuna per il futuro.</p>\r\n\r\n\r\n\r\n            <p>Cordiali saluti,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Firma</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(42, 'ja', '<h3 style=\"text-align: center;\">異議なし証明書</h3>\r\n\r\n\r\n\r\n            <p>日付: {date}</p>\r\n\r\n\r\n\r\n            <p>関係者各位</p>\r\n\r\n\r\n\r\n            <p>この証明書は、Ms. / Mr. {employee_name} が他の組織に参加してサービスを提供する場合に、異議なし証明書 (NoC) を請求するためのものです。彼女/彼/彼がすべての残高を清算し、{app_name} 会社から彼女/彼のセキュリティを受け取ったことが通知されます。</p>\r\n\r\n\r\n\r\n            <p>彼女/彼の今後の幸運を祈っています。</p>\r\n\r\n\r\n\r\n            <p>心から、</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>サイン</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(43, 'nl', '<h3 style=\"text-align: center;\">Geen bezwaarcertificaat</h3>\r\n\r\n\r\n\r\n            <p>Datum: {date}</p>\r\n\r\n\r\n\r\n            <p>Aan wie het ook aangaat</p>\r\n\r\n\r\n\r\n            <p>Dit certificaat is bedoeld om aanspraak te maken op een Geen Bezwaarcertificaat (NoC) voor mevrouw/dhr. {employee_name} als zij/hij lid wordt en haar/zijn diensten verleent aan een andere organisatie. Het wordt ge&iuml;nformeerd als zij/hij al haar/zijn saldos heeft gewist en haar/zijn zekerheid heeft ontvangen van {app_name} Company.</p>\r\n\r\n\r\n\r\n            <p>We wensen haar/hem veel succes in de toekomst.</p>\r\n\r\n\r\n\r\n            <p>Eerlijk,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Handtekening</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(44, 'pl', '<h3 style=\"text-align: center;\">Certyfikat braku sprzeciwu</h3>\r\n\r\n\r\n\r\n            <p>Data: {date}</p>\r\n\r\n\r\n\r\n            <p>Do kogo to może dotyczyć</p>\r\n\r\n\r\n\r\n            <p>Ten certyfikat służy do ubiegania się o Certyfikat No Objection Certificate (NoC) dla Pani/Pana {employee_name}, jeśli ona/ona dołącza i świadczy swoje usługi na rzecz jakiejkolwiek innej organizacji. Jest o tym informowany, ponieważ wyczyścił wszystkie swoje salda i otrzymał swoje zabezpieczenie od firmy {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Życzymy jej/jej powodzenia w przyszłości.</p>\r\n\r\n\r\n\r\n            <p>Z poważaniem,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Podpis</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(45, 'pt', '<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n\r\n\r\n\r\n            <p>Data: {date}</p>\r\n\r\n\r\n\r\n            <p>A quem interessar</p>\r\n\r\n\r\n\r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n\r\n\r\n\r\n            <p>Sinceramente,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Assinatura</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(46, 'ru', '<h3 style=\"text-align: center;\">Сертификат об отсутствии возражений</h3>\r\n\r\n\r\n\r\n            <p>Дата: {date}</p>\r\n\r\n\r\n\r\n            <p>Кого бы это ни касалось</p>\r\n\r\n\r\n\r\n            <p>Этот сертификат предназначен для получения Сертификата об отсутствии возражений (NoC) для г-жи / г-на {employee_name}, если она / он присоединяется и предоставляет свои услуги любой другой организации. Сообщается, что она/он очистила все свои балансы и получила свою безопасность от компании {app_name}.</p>\r\n\r\n\r\n\r\n            <p>Мы желаем ей/ему удачи в будущем.</p>\r\n\r\n\r\n\r\n            <p>Искренне,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Подпись</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(47, 'tr', '<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong>İtiraz Yok Sertifikası</strong></span></p>\r\n\r\n            <p>Tarih: {tarih</p>\r\n\r\n            <p>İlgilendiği Kişiye</p>\r\n\r\n            <p>Bu sertifika, {employee_name} Hanımefendi başka bir kuruluşa katılır ve hizmetlerini sunarsa, İtiraz Yok Sertifikası (NoC) talep etmek içindir. Tüm bakiyelerini kapattığı ve teminatını {app_name} Şirketinden aldığı bilgisi verilir.</p>\r\n\r\n            <p>Kendisine gelecekte iyi şanslar diliyoruz.</p>\r\n\r\n            <p>Saygılarımızla,</p>\r\n            <p>{çalışan_adı}</p>\r\n            <p>{gösterim</p>\r\n            <p>İmza</p>\r\n            <p>{uygulama_adı}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56'),
(48, 'pt-br', '<h3 style=\"text-align: center;\">Certificado de n&atilde;o obje&ccedil;&atilde;o</h3>\r\n\r\n            <p>Data: {date}</p>\r\n\r\n            <p>A quem interessar</p>\r\n\r\n            <p>Este certificado &eacute; para reivindicar um Certificado de N&atilde;o Obje&ccedil;&atilde;o (NoC) para a Sra. / Sr. {employee_name} se ela ingressar e fornecer seus servi&ccedil;os a qualquer outra organiza&ccedil;&atilde;o. &Eacute; informado que ela cancelou todos os seus saldos e recebeu sua garantia da empresa {app_name}.</p>\r\n\r\n            <p>Desejamos-lhe boa sorte no futuro.</p>\r\n\r\n            <p>Sinceramente,</p>\r\n\r\n            <p>{employee_name}</p>\r\n\r\n            <p>{designation}</p>\r\n\r\n            <p>Assinatura</p>\r\n\r\n            <p>{app_name}</p>', 9, '2024-07-03 04:09:56', '2024-07-03 04:09:56');
