INSERT INTO `templates` (`id`, `template_name`, `prompt`, `module`, `field_json`, `is_tone`, `created_at`, `updated_at`) VALUES
(1, 'leave_reason', 'Generate a comma-separated string of common leave reasons that employees may provide to their employers. Include both personal and professional reasons for taking leave, such only ##type## . Aim to generate a diverse range of leave reasons that can be used in different situations. Please provide a comprehensive and varied list of leave reasons that can help employers understand and accommodate their employees\' needs.', 'leave', '{\"field\":[{\"label\":\"Leave Type\",\"placeholder\":\"e.g.illness, family emergencies,vacation\",\"field_type\":\"text_box\",\"field_name\":\"type\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(2, 'subject', 'Generate a goal subject for an employee\'s goal related type to ##type##.', 'goal tracking', '{\"field\":[{\"label\":\"Goal Type\",\"placeholder\":\"e.g.invoice, production,hiring\",\"field_type\":\"text_box\",\"field_name\":\"type\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(3, 'description', 'Generate a goal descriptions for an employee\'s goal title is ##title##.', 'goal tracking', '{\"field\":[{\"label\":\"Goal Title\",\"placeholder\":\"e.g.Invoice Accuracy\",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(4, 'description', 'Generate a job training descriptions for a ##position## position. The training description should include responsibilities such as ##responsibilities##. Please ensure the descriptions are concise, informative, and accurately reflect the key responsibilities of a ##position##.', 'training', '{\"field\":[{\"label\":\"Position\",\"placeholder\":\"job training descriptions\",\"field_type\":\"text_box\",\"field_name\":\"position\"},{\"label\":\"Responsibilities\",\"placeholder\":\"Managing training logistics\",\"field_type\":\"textarea\",\"field_name\":\"responsibilities\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(5, 'title', 'Generate a list of job titles commonly found in an ##work_place##. The job titles should cover a range of roles and responsibilities within the field of ##field##. Include positions such as ##positions##. Please provide a diverse selection of job titles that accurately reflect the various positions found in an ##work_place##.', 'job', '{\"field\":[{\"label\":\"Work Place\",\"placeholder\":\"e.g.IT Company,hospital\",\"field_type\":\"text_box\",\"field_name\":\"work_place\"},{\"label\":\"Field \",\"placeholder\":\"e.g.Backend\",\"field_type\":\"text_box\",\"field_name\":\"field\"},{\"label\":\"Positions\",\"placeholder\":\"e.g.developer,tester\",\"field_type\":\"text_box\",\"field_name\":\"positions\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(6, 'description', 'Generate a job descriptions for a ##position## position. The job description should include responsibilities such as ##responsibilities##. Please ensure the descriptions are concise, informative, and accurately reflect the key responsibilities of a ##position##.', 'job', '{\"field\":[{\"label\":\"Position\",\"placeholder\":\"job for a position\",\"field_type\":\"text_box\",\"field_name\":\"position\"},{\"label\":\"Responsibilities\",\"placeholder\":\"\",\"field_type\":\"textarea\",\"field_name\":\"responsibilities\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(7, 'requirement', 'Generate a comma-separated string of job requirements for a ##position## position. The requirements should include ##description##. Please provide the requirements in a comma-separated string format.', 'job', '{\"field\":[{\"label\":\"Position\",\"placeholder\":\"requirement of job\",\"field_type\":\"text_box\",\"field_name\":\"position\"},{\"label\":\"Description\",\"placeholder\":\"\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(8, 'description', 'Generate a description for presenting the Award. The description should highlight ##reasons##. Emphasize the significance of the  Award as a symbol of recognition for employee\'s remarkable accomplishments and its representation of her \'##reasons##\' and impact on the organization. Please create a personalized and engaging description that conveys appreciation, pride, and gratitude for employee\'s contributions to the company\'s sucess', 'award', '{\"field\":[{\"label\":\"Award reasons\",\"placeholder\":\"e.g.skilled, focused ,efficiency\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(9, 'description', 'Generate a list of common reasons for employee transfers within an organization. Include reasons such as ##reasons##. Please provide a comprehensive and varied list of reasons that can help employers understand and address employee transfer situations effectively.', 'transfer', '{\"field\":[{\"label\":\"Transfer reasons\",\"placeholder\":\"e.g.career development,special projects or initiatives\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(10, 'description', 'Generate a description why an employee might choose to resign and request a transfer to another location within the company. Include both professional and personal reasons that could contribute to this decision. Examples may include ##reasons##. Aim to provide a comprehensive and varied description that can help employers understand and accommodate employees\' needs when considering a transfer request', 'resignation', '{\"field\":[{\"label\":\"Resignation reasons\",\"placeholder\":\"e.g.career development,health issues\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(11, 'description', 'Generate a description for organizing a company trip. The trip aims to ##aims## . Please provide a diverse description that highlight the benefits and positive outcomes associated with organizing a company trip. Focus on creating an engaging and enjoyable experience for employees while also achieving business objectives and cultivating a positive work environment.', 'travel', '{\"field\":[{\"label\":\"Aims\",\"placeholder\":\"e.g.career development,health issues\",\"field_type\":\"textarea\",\"field_name\":\"aims\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(12, 'promotion_title', 'Generate a list of promotion title suggestions for an ##role##. The promotion titles should reflect ##reasons##, and recognition of the ##role##\'s accomplishments. Please provide a diverse range of promotion titles that align with ##role## job roles and levels within the company. Aim to create titles that are both professional and descriptive, highlighting the ##role##\'s progression and impact within the organization.', 'promotion', '{\"field\":[{\"label\":\"Job\",\"placeholder\":\"e.g.doctor, developer\",\"field_type\":\"text_box\",\"field_name\":\"role\"},{\"label\":\"Promotion Reasons\",\"placeholder\":\"e.g.increased responsibility, higher position\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(13, 'description', 'Generate a promotion description for this title:##title##. ', 'promotion', '{\"field\":[{\"label\":\"Promotion Title\",\"placeholder\":\"e.g.Medical Director\",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(14, 'title', 'Generate a list of titles for complaints related to employee and company issues. ##reasons##. Please provide a range of titles that accurately reflect common complaint categories, ensuring they are concise, descriptive, and effective in conveying the nature of the complaint. ', 'complaint', '{\"field\":[{\"label\":\"Complaint reasons\",\"placeholder\":\"e.g.unprofessional behavior, harassment,\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(15, 'description', 'Generate a Complaint description for this title:##title##. ', 'complaint', '{\"field\":[{\"label\":\"Complaint Title\",\"placeholder\":\"e.g.Unprofessional Behavior Complaint\",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(16, 'description', 'Generate a warning description for an employee who consistently ##reasons##. The warning should address the employee\'s ##reasons##, including further disciplinary action or termination of employment. Please provide a clear and firm warning message that encourages the employee to review the policy and make immediate improvements.', 'warning', '{\"field\":[{\"label\":\"Warning reasons\",\"placeholder\":\"e.g.break attendance policy\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(17, 'description', 'Generate a termination description for  the reason :##reason##. The description should convey the company\'s regret over the decision and outline the specific concerns, such as ##reasons##. Please provide a clear and professional message that explains the decision while expressing appreciation for the employee\'s contributions. Aim to offer guidance for personal and professional growth and provide necessary instructions regarding final paycheck and return of company property.', 'termination', '{\"field\":[{\"label\":\"Termination reasons\",\"placeholder\":\"e.g.Poor Performance\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(18, 'description', 'Generate an announcement title for ##reasons##. The title should be attention-grabbing and informative, effectively conveying the key message to the intended audience. Please ensure the title is appropriate for the given situation, whether it\'s about a ##reasons##. Aim to create a title that captures the essence of the announcement and sparks interest or curiosity among the readers.', 'announcement', '{\"field\":[{\"label\":\"Announcement reasons\",\"placeholder\":\"e.g.Growth Opportunities\",\"field_type\":\"textarea\",\"field_name\":\"reasons\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(19, 'occasion', 'Generate a list of holiday occasions for celebrations and gatherings. The occasions should cover a variety of holidays and events throughout the year, such as ##name##. Please provide a diverse range of occasions that can be used for hosting parties, organizing special events, or planning festive activities. Aim to offer unique and creative ideas that cater to different cultures, traditions, and preferences.', 'holiday', '{\"field\":[{\"label\":\"Any Specific occasions\",\"placeholder\":\"e.g.Cultural Celebration\",\"field_type\":\"text_box\",\"field_name\":\"name\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(20, 'title', 'Generate a creative and engaging event title for an upcoming event. The event can be a ##type##. Please focus on creating a title that captures the essence of the event, sparks curiosity, and encourages attendance. Aim to make the title memorable, intriguing, and aligned with the purpose and theme of the event. Consider the target audience, event objectives, and any specific keywords or ideas you would like to incorporate', 'event', '{\"field\":[{\"label\":\"Specific type of event\",\"placeholder\":\"e.g.conference, workshop, seminar\",\"field_type\":\"text_box\",\"field_name\":\"name\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(21, 'title', 'Generate a meeting title that is catchy and informative. The title should effectively convey the purpose and focus of the meeting, whether it\'s for ##purpose##. Please aim to create a title that grabs the attention of participants, reflects the importance of the meeting, and provides a clear understanding of what will be discussed or accomplished during the session.', 'meeting', '{\"field\":[{\"label\":\"Meeting purpose\",\"placeholder\":\"e.g.conference, workshop\",\"field_type\":\"textarea\",\"field_name\":\"purpose\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(22, 'description', 'Generate a descriptive response for a given ##title##. The response should be detailed, engaging, and informative, providing relevant information and capturing the reader\'s interest', 'account asset', '{\"field\":[{\"label\":\"Asset name\",\"placeholder\":\"HR may provide some devices \",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(23, 'description', 'Generate a description based on a given document name:##name##. The document name: ##name## represents a specific file or document, and you need a descriptive summary or overview of its contents. Please provide a clear and concise description that captures the main points, purpose, or key information contained within the document. Aim to create a brief but informative description that gives the reader an understanding of what they can expect when accessing or reviewing the document.', 'document', '{\"field\":[{\"label\":\"Asset name\",\"placeholder\":\"e.g. Employee handbook\",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(24, 'title', 'Generate a suitable title for the company policy regarding ##description##. The title should be clear, concise, and informative, effectively conveying the purpose and scope of the policy. Please ensure that the title reflects the importance of ##description##. Aim to create a title that is professional, easily understandable, and aligned with the company\'s culture and values.', 'company policy', '{\"field\":[{\"label\":\"Description of policy\",\"placeholder\":\"e.g.Leave policies,Performance management\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(25, 'description', 'generate description for this title ##title##', 'chart of account', '{\"field\":[{\"label\":\" Title \",\"placeholder\":\"e.g.Accounts Receivable,Office Equipment\",\"field_type\":\"textarea\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(26, 'description', 'generate description for this title ##title##', 'journal entry', '{\"field\":[{\"label\":\" Title \",\"placeholder\":\"e.g.Accounts Receivable,Office Equipment\",\"field_type\":\"textarea\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(27, 'subject', 'Generate a lead subject line for a marketing campaign targeting potential customers for a software development company specializing in web and mobile applications.', 'lead', '{\"field\":[{\"label\":\"Description\",\"placeholder\":\"e.g. Leads represent potential sales opportunities for a business\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(28, 'name', 'generate deal name for this proposal description ##description##', 'deal', '{\"field\":[{\"label\":\"Proposal Description\",\"placeholder\":\"e.g.Collaboration and Partnerships\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(29, 'subject', 'generate contract subject for this contract description ##description##', 'contract', '{\"field\":[{\"label\":\"Proposal Description\",\"placeholder\":\"e.g.Terms and Conditions\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(30, 'description', 'generate contract description for this contract subject ##subject##', 'contract', '{\"field\":[{\"label\":\"Contract Subject\",\"placeholder\":\"e.g.Legal Protection,Terms and Conditions\",\"field_type\":\"textarea\",\"field_name\":\"subject\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(31, 'project_name', 'Create creative product names:  ##description## \n\nSeed words: ##keywords## \n\n', 'project', '{\"field\":[{\"label\":\"Project Description\",\"placeholder\":\"e.g.Efficiency and Optimization,Business Growth and Expansion\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(32, 'name', 'Generate a task name for a project in an ##project_name##, specifically related to ##instruction##.', 'project task', '{\"field\":[{\"label\":\"Project name\",\"placeholder\":\"e.g.Solving Problems\",\"field_type\":\"text_box\",\"field_name\":\"project_name\"},{\"label\":\"Task Instruction\",\"placeholder\":\"e.g.Data Analysis\",\"field_type\":\"textarea\",\"field_name\":\"instruction\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(33, 'title', 'Generate a milestone name for a ##project_name##,specifically related to ##instruction##.', 'project milestone', '{\"field\":[{\"label\":\"Milestone Description\",\"placeholder\":\"e.g.Design Approved\",\"field_type\":\"textarea\",\"field_name\":\"description\"},{\"label\":\" Instruction\",\"placeholder\":\"e.g. incorporated feedback and revisions\",\"field_type\":\"textarea\",\"field_name\":\"instruction\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
