(35, 'description', 'Write a long creative product description for: ##title## \n\nTarget audience is: ##audience## \n\nUse this description: ##description## \n\nTone of generated text must be:\n ##tone_language## \n\n', 'productservice', '{\"field\":[{\"label\":\"Product name\",\"placeholder\":\"e.g. VR, Honda\",\"field_type\":\"text_box\",\"field_name\":\"title\"},{\"label\":\"Audience\",\"placeholder\":\"e.g. Women, Aliens\",\"field_type\":\"text_box\",\"field_name\":\"audience\"},{\"label\":\"Product Description\",\"placeholder\":\"e.g. VR is an innovative device that can allow you to be part of virtual world\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(36, 'name', 'generate warehouse name for ##description##', 'warehouse', '{\"field\":[{\"label\":\"Description\",\"placeholder\":\"e.g.North Warehouse\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
