(38, 'description', 'generate support ticket description of  subject for ##subject## ', 'support', '{\"field\":[{\"label\":\"Ticket Subject\",\"placeholder\":\"e.g.Error Message Displayed\",\"field_type\":\"textarea\",\"field_name\":\"subject\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(39, 'title', 'Generate a list of Zoom meeting topics for ##description## metting. The purpose of the meeting is to  ##description##. Structure the topics to ensure a productive discussion.', 'zoom meeting', '{\"field\":[{\"label\":\"Meeting description \",\"placeholder\":\"e.g.Remote Collaboration\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(40, 'content', 'Generate a meeting notification message for an ##topic## meeting. Include the date, time, location, and a brief agenda with three key discussion points.', 'notification template', '{\"field\":[{\"label\":\"Notification Message\",\"placeholder\":\"e.g.brief explanation of the purpose or background of the notification\",\"field_type\":\"textarea\",\"field_name\":\"topic\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(41, 'name', 'please suggest subscription plan  name  for this  :  ##description##  for my business', 'plan', '{\"field\":[{\"label\":\"What is your plan about?\",\"placeholder\":\"e.g. Describe your plan details \",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
