(43, 'name', 'give 10 catchy only name of Offer or discount Coupon for : ##keywords##', 'coupon', '{\"field\":[{\"label\":\"Seed words\",\"placeholder\":\"e.g.coupon will provide you with a discount on your selected plan\",\"field_type\":\"text_box\",\"field_name\":\"keywords\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(44, 'meta_title', 'Write SEO meta title for:\n\n ##description## \n\nWebsite name is:\n ##title## \n\nSeed words:\n ##keywords## \n\n', 'seo', '{\"field\":[{\"label\":\"Website Name\",\"placeholder\":\"e.g. Amazon, Google\",\"field_type\":\"text_box\",\"field_name\":\"title\"},{\"label\":\"Website Description\",\"placeholder\":\"e.g. Describe what your website or business do\",\"field_type\":\"textarea\",\"field_name\":\"description\"},{\"label\":\"Keywords\",\"placeholder\":\"e.g.  cloud services, databases\",\"field_type\":\"text_box\",\"field_name\":\"keywords\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(45, 'meta_desc', 'Write SEO meta description for:\n\n ##description## \n\nWebsite name is:\n ##title## \n\nSeed words:\n ##keywords## \n\n', 'seo', '{\"field\":[{\"label\":\"Website Name\",\"placeholder\":\"e.g. Amazon, Google\",\"field_type\":\"text_box\",\"field_name\":\"title\"},{\"label\":\"Website Description\",\"placeholder\":\"e.g. Describe what your website or business do\",\"field_type\":\"textarea\",\"field_name\":\"description\"},{\"label\":\"Keywords\",\"placeholder\":\"e.g.  cloud services, databases\",\"field_type\":\"text_box\",\"field_name\":\"keywords\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(46, 'cookie_title', 'please suggest me cookie title for this ##description## website which i can use in my website cookie', 'cookie', '{\"field\":[{\"label\":\"Website name or info\",\"placeholder\":\"e.g. example website \",\"field_type\":\"textarea\",\"field_name\":\"title\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(47, 'cookie_description', 'please suggest me  Cookie description for this cookie title ##title##  which i can use in my website cookie', 'cookie', '{\"field\":[{\"label\":\"Cookie Title \",\"placeholder\":\"e.g. example website \",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(48, 'strictly_cookie_title', 'please suggest me only Strictly Cookie Title for this ##description## website which i can use in my website cookie', 'cookie', '{\"field\":[{\"label\":\"Website name or info\",\"placeholder\":\"e.g. example website \",\"field_type\":\"textarea\",\"field_name\":\"title\"}]}', 0, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(49, 'strictly_cookie_description', 'please suggest me Strictly Cookie description for this Strictly cookie title ##title##  which i can use in my website cookie', 'cookie', '{\"field\":[{\"label\":\"Strictly Cookie Title \",\"placeholder\":\"e.g. example website \",\"field_type\":\"text_box\",\"field_name\":\"title\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(50, 'more_information_description', 'I need assistance in crafting compelling content for my ##web_name## website\'s \'Contact Us\' page of my website. The page should provide relevant information to users, encourage them to reach out for inquiries, support, and feedback, and reflect the unique value proposition of my business.', 'cookie', '{\"field\":[{\"label\":\"Websit Name\",\"placeholder\":\"e.g. example website \",\"field_type\":\"text_box\",\"field_name\":\"web_name\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(51, 'content', 'generate email template for ##type##', 'email template', '{\"field\":[{\"label\":\"Email Type\",\"placeholder\":\"e.g. new user,new client\",\"field_type\":\"text_box\",\"field_name\":\"type\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(52, 'note', 'Generate short description Note for lead ##description##', 'lead', '{\"field\":[{\"label\":\"Lead description\",\"placeholder\":\"e.g. create notes for lead user \",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(53, 'description', 'Generate a short note summarizing the key points discussed during a lead ##name## call. The purpose of the note is to capture important details and action items discussed with the ##name## lead. Please structure the note in a concise and organized manner.', 'lead', '{\"field\":[{\"label\":\"Lead name\",\"placeholder\":\"e.g. create description for lead user \",\"field_type\":\"textarea\",\"field_name\":\"name\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(54, 'note', 'Generate short description Note for deal ##description##', 'deal', '{\"field\":[{\"label\":\"Deal description\",\"placeholder\":\"e.g.create note for deal client\",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25'),
(55, 'description', 'Generate a short note summarizing a deal call. Imagine you just had a call with a potential client or partner to discuss a ##description## deal. Write a concise summary of the key points discussed during the call. Include the important details such as the client\'s name, the purpose of the call, any agreements or decisions made, and next steps to be taken.', 'deal', '{\"field\":[{\"label\":\"Deal name\",\"placeholder\":\"e.g. Establishing Communication \",\"field_type\":\"textarea\",\"field_name\":\"description\"}]}', 1, '2024-06-08 05:56:25', '2024-06-08 05:56:25');
